CREATE TABLE IF NOT EXISTS psych_drugs (
  id BIGINT UNSIGNED NOT NULL AUTO_INCREMENT,
  `ingredient_name` VARCHAR(255) NULL,
  `product_name` VARCHAR(255) NULL,
  `dosage` VARCHAR(255) NULL,
  `usage` LONGTEXT NULL,
  `efficacy` LONGTEXT NULL,
  `side_effects` LONGTEXT NULL,
  `precautions` LONGTEXT NULL,
  `contraindications` LONGTEXT NULL,
  `cautious_patients` LONGTEXT NULL,
  created_at DATETIME(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6),
  updated_at DATETIME(6) NOT NULL DEFAULT CURRENT_TIMESTAMP(6) ON UPDATE CURRENT_TIMESTAMP(6),
  PRIMARY KEY (id)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
CREATE INDEX `idx_psych_drugs_product_name` ON `psych_drugs` (`product_name`);
CREATE INDEX `idx_psych_drugs_ingredient_name` ON `psych_drugs` (`ingredient_name`);

INSERT INTO psych_drugs (`ingredient_name`, `product_name`, `dosage`, `usage`, `efficacy`, `side_effects`, `precautions`, `contraindications`, `cautious_patients`) VALUES

('메틸페니데이트 (Methylphenidate Hydrochloride)', '콘서타오로스서방정(콘서타OROS서방정)18mg', '18mg', '1일 1회 오전', '주의력결핍, 과잉행동, 충동성 등 ADHD의 핵심증상에 가장 강력하고 즉각적인 효과', '불면, 식욕감소, 두통, 복통, 틱 ,신경과민, 불안, 우울감, 어지러움, 입안 건조, 구역, 체중감', '이 약은 물과 함께 정제 그대로 복용해야 한다. 정제를 씹거나 자르거나 분쇄해서는 안된다. 이 약은 음식과 함께 복용하여도 무관하다. ', '중증의 불안, 긴장, 흥분 환자, MAO 저해제 투여 중이거나, MAO 저해제 투여 중단 후 최소 14일 이내의 환자, 이 약 및 이 약의 다른 성분에 과민증이 있는 환자, 유당불내증, 뇌혈관장애환자 ', '정신질환 환자 (메틸페니데이트 투여로 행동장애 및 사고장해 증상이 악화될 수 있다),고혈압 환자 및 심박수나 혈압이 상승될 수 있는 의학적 상태의 환자(주기적으로 심혈관 상태를 모니터링해야한다), 약물의존성 또는 알코올중독의 병력이 있는 환자, 발작 병력이 있는 환자(경련 역치가 저하될 수 있다)'),
